INSERT INTO public.campaigns (id, name, type, start_date, end_date, status, description, target_stores, budget, actual_cost, created_at, updated_at) VALUES ('ca-real-001', 'G5 Launch Promotion', '新品上市', '2026-06-03', '2026-06-18', 'completed', 'G5 flagship device launch campaign targeting A-level stores. Demo events, staff training, and POSM rollout. Goal: establish G5 as premium pod system in market.', '["s-real-012", "s-real-013", "s-real-014", "s-real-032", "s-real-035", "s-real-036", "s-real-039"]'::jsonb, 25000, 21800, '2026-05-29T05:31:12.402Z', '2026-06-18T05:31:12.402Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.campaigns (id, name, type, start_date, end_date, status, description, target_stores, budget, actual_cost, created_at, updated_at) VALUES ('ca-real-002', 'Ramadan Vape Giveaway', '节日营销', '2026-06-08', '2026-06-21', 'completed', 'Ramadan holiday promotion: buy 2 G4 devices get 1 pod free. QR scan earns double points. Covered A and B level stores across Riyadh.', '["s-real-012", "s-real-013", "s-real-014", "s-real-032", "s-real-035", "s-real-036", "s-real-039", "s-real-001", "s-real-003", "s-real-004", "s-real-006", "s-real-007", "s-real-008", "s-real-010", "s-real-011"]'::jsonb, 18000, 16500, '2026-06-03T05:31:12.402Z', '2026-06-21T05:31:12.402Z') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.campaigns (id, name, type, start_date, end_date, status, description, target_stores, budget, actual_cost, created_at, updated_at) VALUES ('ca-real-003', 'Store Display Upgrade Program', '渠道建设', '2026-06-13', '2026-07-13', 'ongoing', 'Provide UWELL lightbox + acrylic stand to top 20 stores. Goal: increase shelf visibility and brand presence. Stores with lightbox sell 2.3x more.', '["s-real-012", "s-real-013", "s-real-014", "s-real-032", "s-real-035", "s-real-036", "s-real-039", "s-real-001", "s-real-003", "s-real-004", "s-real-006", "s-real-007", "s-real-008", "s-real-010", "s-real-011", "s-real-016", "s-real-020", "s-real-022", "s-real-024", "s-real-025"]'::jsonb, 30000, 14200, '2026-06-08T05:31:12.402Z', '2026-06-22T05:31:12.402Z') ON CONFLICT (id) DO NOTHING;
