INSERT INTO public.campaign_reports (id, campaign_id, report_date, total_sales, total_visits, total_scans, total_participants, achievement_rate, cost_ratio, summary, improvements, photos, created_at, updated_at) VALUES ('cr-001', 'ca-001', '2026-06-20', 12500, 45, 320, 5, 105, 84, '夏季清凉饮品促销周圆满结束，5家门店参与，总销售额12500元，超额完成5%。橙汁和矿泉水动销最佳，展架陈列效果显著。建议后续类似活动继续采用试吃+买赠组合策略。', '1. 部分门店补货不够及时，下次需提前协调库存；2. 试用装消耗超预期，需增加备货；3. 可考虑增加线上扫码领券引流到店。', '["https://images.unsplash.com/photo-1626202378011-4b0bf3a99fcd?w=400"]'::jsonb, '2026-06-20T05:31:12.402Z', '2026-06-20T05:31:12.402Z') ON CONFLICT (id) DO NOTHING;
