-- ===== Community Posts (12) =====
CREATE TABLE IF NOT EXISTS public.community_posts (
  id TEXT PRIMARY KEY,
  author_name TEXT DEFAULT 'Anonymous',
  content TEXT NOT NULL,
  category TEXT DEFAULT 'Discussion',
  likes INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
ALTER TABLE public.community_posts ENABLE ROW LEVEL SECURITY;
CREATE POLICY "community_posts_select" ON public.community_posts FOR SELECT USING (true);
CREATE POLICY "community_posts_all" ON public.community_posts FOR ALL USING (true);


-- ===== Community Comments (20) =====
CREATE TABLE IF NOT EXISTS public.community_comments (
  id TEXT PRIMARY KEY,
  post_id TEXT NOT NULL REFERENCES public.community_posts(id) ON DELETE CASCADE,
  author_name TEXT DEFAULT 'Anonymous',
  content TEXT NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
ALTER TABLE public.community_comments ENABLE ROW LEVEL SECURITY;
CREATE POLICY "community_comments_select" ON public.community_comments FOR SELECT USING (true);
CREATE POLICY "community_comments_all" ON public.community_comments FOR ALL USING (true);


